import { Stack, ToggleButton, ToggleButtonGroup, Typography } from "@mui/material";

import { ExpenseStatus } from "@/services/types";

export function StatusFilter({
  value,
  onChange
}: {
  value: ExpenseStatus | "all";
  onChange: (value: ExpenseStatus | "all") => void;
}) {
  return (
    <Stack spacing={1}>
      <Typography variant="subtitle2">Filter by status</Typography>
      <ToggleButtonGroup
        exclusive
        size="small"
        value={value}
        aria-label="Filter by status"
        onChange={(_, next) => {
          if (next) onChange(next as ExpenseStatus | "all");
        }}
      >
        <ToggleButton value="all">All</ToggleButton>
        <ToggleButton value="planned">Planned</ToggleButton>
        <ToggleButton value="purchased">Purchased</ToggleButton>
        <ToggleButton value="canceled">Canceled</ToggleButton>
      </ToggleButtonGroup>
    </Stack>
  );
}
