import { ReactNode } from "react";
import {
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Typography
} from "@mui/material";

export type DataTableColumn<T> = {
  key: string;
  header: string;
  render: (row: T) => ReactNode;
};

export function DataTable<T extends { id: string }>({
  columns,
  rows
}: {
  columns: DataTableColumn<T>[];
  rows: T[];
}) {
  if (rows.length === 0) return <Typography color="text.secondary">No items to display.</Typography>;
  return (
    <TableContainer component={Paper} variant="outlined">
      <Table size="small" aria-label="data table">
        <TableHead>
          <TableRow>
          {columns.map((column) => (
              <TableCell key={column.key} sx={{ fontWeight: 700 }}>
                {column.header}
              </TableCell>
          ))}
          </TableRow>
        </TableHead>
        <TableBody>
        {rows.map((row) => (
            <TableRow key={row.id}>
            {columns.map((column) => (
                <TableCell key={`${row.id}-${column.key}`}>{column.render(row)}</TableCell>
            ))}
            </TableRow>
        ))}
        </TableBody>
      </Table>
    </TableContainer>
  );
}
