import { Alert, CircularProgress, Stack } from "@mui/material";

export function FeedbackState({
  state,
  message
}: {
  state: "idle" | "loading" | "error" | "success";
  message?: string;
}) {
  if (state === "idle") return null;
  if (state === "loading") {
    return (
      <Stack direction="row" spacing={1} alignItems="center" role="status" aria-live="polite">
        <CircularProgress size={16} />
        <span>{message ?? "Loading..."}</span>
      </Stack>
    );
  }
  if (state === "success") return <Alert severity="success">{message ?? "Saved successfully."}</Alert>;
  return <Alert severity="error">{message ?? "Something went wrong."}</Alert>;
}
