"use client";

import { use, useEffect, useMemo, useRef, useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { Alert, Button, Card, CardContent, Stack, Typography } from "@mui/material";

import { DeleteExpenseDialog } from "@/components/expenses/delete-expense-dialog";
import { ExpenseFormDialog, ExpenseFormPayload } from "@/components/expenses/expense-form-dialog";
import { ExpenseList } from "@/components/expenses/expense-list";
import { StatusFilter } from "@/components/expenses/status-filter";
import { YearSummaryCards } from "@/components/summary/year-summary-cards";
import { FeedbackState } from "@/components/ui/feedback-state";
import { startRouteTiming } from "@/lib/performance";
import { createExpense, deleteExpense, fetchExpenses, fetchYearSummary, updateExpense } from "@/services/expenses";
import { Expense, ExpenseStatus } from "@/services/types";

type PageProps = {
  params: Promise<{
    year: string;
  }>;
};

export default function YearPage({ params }: PageProps) {
  const { year: yearParam } = use(params);
  const year = Number(yearParam);
  const queryClient = useQueryClient();
  const [statusFilter, setStatusFilter] = useState<ExpenseStatus | "all">("all");
  const [state, setState] = useState<"idle" | "loading" | "error" | "success">("idle");
  const [message, setMessage] = useState("");
  const [editing, setEditing] = useState<Expense | null>(null);
  const [deleting, setDeleting] = useState<Expense | null>(null);
  const [showCreate, setShowCreate] = useState(false);
  const [routeDuration, setRouteDuration] = useState<number | null>(null);
  const endTimingRef = useRef<(() => number) | null>(null);

  const expensesQuery = useQuery({
    queryKey: ["expenses", year, statusFilter],
    queryFn: () => fetchExpenses(year, statusFilter === "all" ? undefined : statusFilter),
    staleTime: 2 * 60_000,
    placeholderData: (previousData) => previousData
  });

  const summaryQuery = useQuery({
    queryKey: ["summary", year],
    queryFn: () => fetchYearSummary(year),
    staleTime: 2 * 60_000,
    placeholderData: (previousData) => previousData
  });

  const formOpen = showCreate || Boolean(editing);

  async function refreshData() {
    await Promise.all([
      queryClient.invalidateQueries({ queryKey: ["expenses", year] }),
      queryClient.invalidateQueries({ queryKey: ["summary", year] })
    ]);
  }

  async function handleSave(payload: ExpenseFormPayload & { version?: number }) {
    setState("loading");
    try {
      if (editing) {
        await updateExpense(editing.id, { ...payload, version: editing.version });
        setMessage("Expense updated.");
      } else {
        await createExpense(year, payload);
        setMessage("Expense created.");
      }
      setState("success");
      setEditing(null);
      setShowCreate(false);
      await refreshData();
    } catch (error) {
      setState("error");
      setMessage(error instanceof Error ? error.message : "Unable to save expense.");
    }
  }

  async function handleDelete() {
    if (!deleting) return;
    setState("loading");
    try {
      await deleteExpense(deleting.id);
      setState("success");
      setMessage("Expense deleted.");
      setDeleting(null);
      await refreshData();
    } catch (error) {
      setState("error");
      setMessage(error instanceof Error ? error.message : "Unable to delete expense.");
    }
  }

  const loading = expensesQuery.isPending || summaryQuery.isPending;
  const hasError = expensesQuery.isError || summaryQuery.isError;
  const expenses = expensesQuery.data ?? [];
  const empty = !loading && !hasError && expenses.length === 0;

  useEffect(() => {
    endTimingRef.current = startRouteTiming(`/years/${year}`);
    setRouteDuration(null);
  }, [year]);

  useEffect(() => {
    if (!loading && endTimingRef.current) {
      const duration = endTimingRef.current();
      endTimingRef.current = null;
      setRouteDuration(duration);
    }
  }, [loading]);

  const heading = useMemo(() => `Planner ${year}`, [year]);

  return (
    <Stack spacing={2}>
      <Card>
        <CardContent sx={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 2, flexWrap: "wrap" }}>
          <div>
            <Typography variant="h4">{heading}</Typography>
            <Typography color="text.secondary">
            Track planned, purchased, and canceled expenses.
            </Typography>
          </div>
          <Button variant="contained" onClick={() => setShowCreate(true)}>
            Add expense
          </Button>
        </CardContent>
      </Card>

      <FeedbackState state={state} message={message} />

      {loading ? <Alert severity="info">Loading annual data...</Alert> : null}
      {hasError ? <Alert severity="error">Unable to load annual data.</Alert> : null}

      {!loading && !hasError && summaryQuery.data ? <YearSummaryCards summary={summaryQuery.data} /> : null}

      {!loading && !hasError ? (
        <Card>
          <CardContent>
          <StatusFilter value={statusFilter} onChange={setStatusFilter} />
          {empty ? (
              <Typography color="text.secondary" sx={{ mt: 2 }}>
                No expenses yet for this view. Create the first one to start planning.
              </Typography>
          ) : (
            <ExpenseList expenses={expenses} onEdit={setEditing} onDelete={setDeleting} />
          )}
          </CardContent>
        </Card>
      ) : null}

      {!loading && routeDuration !== null ? (
        <Typography variant="caption" color="text.secondary">
          View loaded in {Math.round(routeDuration)}ms
        </Typography>
      ) : null}

      {formOpen ? (
        <ExpenseFormDialog
          expense={editing ?? undefined}
          onSave={handleSave}
          onCancel={() => {
            setEditing(null);
            setShowCreate(false);
          }}
        />
      ) : null}

      {deleting ? (
        <DeleteExpenseDialog title={deleting.title} onConfirm={handleDelete} onCancel={() => setDeleting(null)} />
      ) : null}
    </Stack>
  );
}
